"use strict";parserFactory.register("wuxiaworld.world",()=>new WuxiaworldWorldParser);class WuxiaworldWorldParser extends Parser{constructor(){super()}getChapterUrls(e){let r=e.querySelector("div.manga_chapter_list");return Promise.resolve(util.hyperlinksToChapterList(r).reverse())}findContent(e){return e.querySelector("div.list_img")}extractTitleImpl(e){return e.querySelector("div.manga_name h1")}extractAuthor(e){let r=e.querySelector("div.manga_des a");return null===r?super.extractAuthor(e):r.textContent}findChapterTitle(e){return e.querySelector("div.manga_view_name h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.manga_info_img")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.manga_description")]}}